    public static void insertLog(PurchReqTable _purchReqTable, str _lineNum, PurchTable _purchTable,str _nonSubmisionCause)
    {
        UBSPrTransformToPoLog prTransformToPoLog;

        ttsbegin;
        if(_purchReqTable)
        {
            container wfApproverAndTime             = _purchReqTable.UbsGetWFLastApproverAndValidationTime();
            prTransformToPoLog.PurchReqId           = _purchReqTable.PurchReqId;
            prTransformToPoLog.UBSLastValidator     = conPeek(wfApproverAndTime,1);
            prTransformToPoLog.UBSValidationTime    = conPeek(wfApproverAndTime,2);

            if(!_purchTable)
            {
                PurchReqLine prl;

                select firstfast prl
                    where prl.PurchReqTable == _purchReqTable.RecId;

                prTransformToPoLog.UBSAreaId = prl.buyingLegalEntity2DataArea();
            }
        }

        if(_purchTable)
        {
            prTransformToPoLog.PurchId      = _purchTable.PurchId;
            prTransformToPoLog.UBSAreaId    = _purchTable.DataAreaId;
        }

        prTransformToPoLog.LinesNumber              = _lineNum;
        prTransformToPoLog.UBSNonSubmissionCause    = _nonSubmisionCause;
        prTransformToPoLog.insert();
        ttscommit;
    }
